<template><div class="panel-section"><div class="section-row"><div><h2 class="section-heading">Cases／研究參與者</h2><p class="section-sub">一般畫面保留本名；匿名代號只用於匯出。</p></div><button class="btn btn-primary" @click="open()">＋ 新增 Case</button></div>
<div class="cases-grid"><div class="card"><button v-for="c in store.cases" :key="c.id" class="case-item" @click="open(c)"><strong>{{c.name}}</strong><span>{{c.role==='researcher'?'研究者':'參與者'}} · {{label(c)}}</span></button></div><div class="card"><template v-if="editing"><div class="form-group"><label class="form-label">姓名</label><input class="form-input" v-model="form.name"></div><div class="form-group"><label class="form-label">角色</label><select class="form-select" v-model="form.role"><option value="participant">Participant</option><option value="researcher">Researcher</option></select></div><div class="form-group"><label class="form-label">Aliases（每行一個）</label><textarea class="form-textarea" v-model="aliases"></textarea></div><div class="form-group"><label class="form-label">Case memo</label><textarea class="form-textarea" v-model="form.memo"></textarea></div><template v-if="editing.id"><div v-for="d in store.attributeDefinitions" :key="d.id" class="form-group"><label class="form-label">{{d.name}} <small>({{d.data_type}})</small></label><input v-if="d.data_type==='text'||d.data_type==='date'||d.data_type==='number'" class="form-input" :type="d.data_type==='date'?'date':d.data_type==='number'?'number':'text'" v-model="attributes[d.id]"><select v-else-if="d.data_type==='boolean'" class="form-select" v-model="attributes[d.id]"><option :value="true">是</option><option :value="false">否</option></select><select v-else class="form-select" v-model="attributes[d.id]"><option v-for="o in d.enum_options" :key="o" :value="o">{{o}}</option></select></div></template><button class="btn btn-primary" @click="save">儲存</button></template><div v-else class="empty-state">選取或新增 Case</div></div></div>
<div class="card"><h3>Attribute definitions</h3><div class="filter-row"><input class="form-input" placeholder="屬性名稱" v-model="definition.name"><select class="form-select" v-model="definition.data_type"><option value="text">文字</option><option value="number">數字</option><option value="boolean">布林</option><option value="date">日期</option><option value="enum">選項</option></select><input v-if="definition.data_type==='enum'" class="form-input" placeholder="選項，以逗號分隔" v-model="enumOptions"><button class="btn btn-secondary" @click="addDefinition">新增定義</button></div></div>
<div class="card"><h3>Speaker 關聯</h3><div v-for="s in speakers" :key="s.speaker_id" class="speaker-link-row"><span>{{s.speaker_name}}</span><select class="form-select" :value="s.case_id||''" @change="link(s,$event.target.value)"><option value="">未關聯</option><option v-for="c in store.cases" :key="c.id" :value="c.id">{{c.name}}</option></select></div></div></div></template>
<script setup>import{ref,computed,reactive}from'vue';import{useAppStore}from'../stores/appStore.js';const store=useAppStore(),editing=ref(null),form=ref({}),aliases=ref(''),attributes=reactive({}),definition=reactive({name:'',data_type:'text'}),enumOptions=ref('');const speakers=computed(()=>[...new Map(store.segments.map(s=>[s.speaker_id,s])).values()].filter(s=>s.speaker_id));function label(c){return`${c.role==='researcher'?'R':'P'}${String(c.anonymous_number).padStart(3,'0')}`}function open(c=null){editing.value=c||{};form.value=c?{...c}:{name:'',role:'participant',memo:''};aliases.value=(c?.aliases||[]).join('\n');for(const k of Object.keys(attributes))delete attributes[k];Object.assign(attributes,c?.attributes||{})}async function save(){const body={...form.value,aliases:aliases.value.split('\n').map(x=>x.trim()).filter(Boolean)};if(editing.value.id){await store.updateCase(editing.value,body);const values={};for(const d of store.attributeDefinitions)if(attributes[d.id]!==''&&attributes[d.id]!=null)values[d.id]=d.data_type==='number'?Number(attributes[d.id]):attributes[d.id];await store.saveCaseAttributes(editing.value.id,values)}else await store.createCase(body);editing.value=null;store.toast('Case 已儲存')}async function addDefinition(){await store.createAttributeDefinition({name:definition.name,data_type:definition.data_type,enum_options:enumOptions.value.split(',').map(x=>x.trim()).filter(Boolean),required:false,sort_order:store.attributeDefinitions.length});definition.name='';enumOptions.value=''}async function link(s,id){await store.linkSpeaker(store.currentInterviewId,s.speaker_id,id||null)}</script>
